// === VERIFICATION ===
console.log('\n=== VERIFICATION ===');
console.log('Total generated:', generated.length);

let allPass = true;
let failCount = 0;
for (const e of generated) {
  const ml = (e.meaning || '').length;
  const al = (e.advice || '').length;
  const wl = (e.warning || '').length;
  const bl = (e.basis || []).length;
  const ok = ml >= 100 && al >= 85 && wl >= 65 && bl >= 4;
  if (!ok) {
    console.log('FAIL:', e.id, 'm='+ml, 'a='+al, 'w='+wl, 'b='+bl);
    allPass = false; failCount++;
  }
}
console.log('Pass:', generated.length - failCount, 'Fail:', failCount);

// Uniqueness checks
function norm(t) { return String(t||'').replace(/[，。、；：！？\s\d]/g,'').substring(0,50); }
let dupIssue = false;
const CATS_ARR = ['general','career','love','money','people','family','study','health','decision','business','legal','spiritual'];
for (const c of CATS_ARR) {
  const me = generated.filter(e => e.category === c).map(e => norm(e.meaning));
  if (new Set(me).size !== 6) { console.log('CAT ' + c + ' SAME-CAT not unique (' + new Set(me).size + '/6)'); dupIssue = true; }
}
for (let l = 1; l <= 6; l++) {
  const me = generated.filter(e => e.line === l).map(e => norm(e.meaning));
  if (new Set(me).size !== 12) { console.log('L' + l + ' SAME-LINE not unique (' + new Set(me).size + '/12)'); dupIssue = true; }
}
if (!dupIssue) console.log('All uniqueness checks PASS');

